// --- NetworkModule.kt ---
package com.example.networking

import com.example.networking.api.UserApiService
import okhttp3.CertificatePinner
import okhttp3.OkHttpClient
import okhttp3.logging.HttpLoggingInterceptor
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import java.util.concurrent.TimeUnit

object NetworkModule {

    private var environment: Environment = Environment.DEV
    private var tokenProvider: TokenProvider? = null
    private var onTokenRefreshFailed: (() -> Unit)? = null

    private var okHttpClient: OkHttpClient? = null
    private var retrofit: Retrofit? = null
    private var userApiService: UserApiService? = null

    fun initialize(
        environment: Environment,
        tokenProvider: TokenProvider,
        onTokenRefreshFailed: (() -> Unit)? = null
    ) {
        this.environment = environment
        this.tokenProvider = tokenProvider
        this.onTokenRefreshFailed = onTokenRefreshFailed
        // Reset cached instances
        okHttpClient = null
        retrofit = null
        userApiService = null
    }

    private fun buildOkHttpClient(): OkHttpClient {
        okHttpClient?.let { return it }

        val provider = tokenProvider
            ?: throw IllegalStateException("NetworkModule not initialized. Call initialize() first.")

        val builder = OkHttpClient.Builder()
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .addInterceptor(AuthInterceptor(provider))
            .authenticator(TokenAuthenticator(provider, onTokenRefreshFailed))

        // Certificate pinning for production and staging
        if (environment == Environment.PRODUCTION || environment == Environment.STAGING) {
            val certificatePinner = CertificatePinner.Builder()
                .add("api.example.com", "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=")
                .add("staging-api.example.com", "sha256/BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=")
                .build()
            builder.certificatePinner(certificatePinner)
        }

        // Logging only for non-production
        if (environment != Environment.PRODUCTION) {
            val loggingInterceptor = HttpLoggingInterceptor().apply {
                level = HttpLoggingInterceptor.Level.BODY
            }
            builder.addInterceptor(loggingInterceptor)
        }

        return builder.build().also { okHttpClient = it }
    }

    private fun buildRetrofit(): Retrofit {
        retrofit?.let { return it }

        return Retrofit.Builder()
            .baseUrl(environment.baseUrl)
            .client(buildOkHttpClient())
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .also { retrofit = it }
    }

    fun getUserApiService(): UserApiService {
        userApiService?.let { return it }

        return buildRetrofit()
            .create(UserApiService::class.java)
            .also { userApiService = it }
    }
}

// --- SafeApiCall.kt ---
package com.example.networking

import com.example.networking.model.ApiResponse
import retrofit2.Response

suspend fun <T> safeApiCall(apiCall: suspend () -> Response<T>): ApiResponse<T> {
    return try {
        val response = apiCall()
        if (response.isSuccessful) {
            val body = response.body()
            if (body != null) {
                ApiResponse.Success(body)
            } else {
                ApiResponse.Error(response.code(), "Empty response body")
            }
        } else {
            val errorMessage = response.errorBody()?.string() ?: "Unknown error"
            ApiResponse.Error(response.code(), errorMessage)
        }
    } catch (e: java.io.IOException) {
        ApiResponse.Exception(e)
    } catch (e: kotlin.Exception) {
        ApiResponse.Exception(e)
    }
}

