package com.example.networking.repository

import com.example.networking.NetworkModule
import com.example.networking.model.ApiResponse
import com.example.networking.model.UserListResponse
import com.example.networking.model.UserProfile
import com.example.networking.safeApiCall

class UserRepository {

    private val apiService = NetworkModule.getUserApiService()

    suspend fun getUsers(page: Int = 1, perPage: Int = 20): ApiResponse<UserListResponse> {
        return safeApiCall { apiService.getUsers(page, perPage) }
    }

    suspend fun getUserProfile(userId: String): ApiResponse<UserProfile> {
        // Input validation
        require(userId.isNotBlank()) { "User ID must not be blank" }
        require(userId.matches(Regex("^[a-zA-Z0-9_-]+$"))) { "Invalid user ID format" }

        return safeApiCall { apiService.getUserProfile(userId) }
    }

    suspend fun getCurrentUserProfile(): ApiResponse<UserProfile> {
        return safeApiCall { apiService.getCurrentUserProfile() }
    }
}

